import { Component, Element, Event, EventEmitter, Host, Listen, Prop, State, h } from '@stencil/core';
import { generateRandId, twMerge } from '../../utils/utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { FOCUSABLE_SELECTORS } from '../../models/pseudo-states.model';

@Component({
  tag: 'wdpr-accordion',
  shadow: true,
})
export class WdprAccordion {

  @Element() el: HTMLElement;

  @State() private _internalId: string;

  @Prop() iconPosition: 'leading' | 'trailing' = 'leading';
  @Prop({ mutable: true, reflect: true }) expanded = false;
  @Prop() header: string = '';
  @Prop() subheader: string = '';
  @Prop() size: 'xxsmall' | 'xsmall' | 'small' | 'medium' | 'large' = 'xsmall';
  @Prop() showTopDivider: boolean = true;
  @Prop() showBottomDivider: boolean = true;
  @Prop() accordionId?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string = '';

  @Event() expandedChanged: EventEmitter<{ expanded: boolean }>;

  componentWillLoad() {
    this._internalId = this.accordionId || `wdpr-accordion-${generateRandId()}`;
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  /**
   * When the accordion is expanded by user interaction, focus the first focusable element inside the accordion content.
   * Uses a timeout to ensure the content is rendered before trying to focus.
   */
  private _focusContentOnExpand = () => {
    if (this.expanded) {
      setTimeout(() => this._focusFirstSlotElement(), 0);
    }
  };

  private _handleClickEvent = () => {
    this.expanded = !this.expanded;
    this.expandedChanged.emit({ expanded: this.expanded });

    this._focusContentOnExpand();
  };

  private _handleKeyDown = (ev: KeyboardEvent) => {
    if (ev.key === KEYBOARD_KEYS.ENTER || ev.key === KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      this.expanded = !this.expanded;
      this.expandedChanged.emit({ expanded: this.expanded });

      this._focusContentOnExpand();
    }
  };

  private _focusFirstSlotElement = () => {
    if (this.expanded) {
      const slot = this.el.shadowRoot?.querySelector<HTMLSlotElement>('slot[name="accordion-content"]');
      if (!slot) return;

      const res = slot.assignedElements({ flatten: true })
        .flatMap(el => Array.from(el.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTORS)))[0];

      res?.focus({ preventScroll: true });
    }
  };

  private get _titleClass() {
    const headingClass = `heading-${this.size}`;

    return twMerge(
      titleBaseClass,
      this.iconPosition == 'leading' ? 'order-1' : 'order-0',
      headingClass
    );
  };

  private get _subheaderClass() {
    let bodySize;
    if (this.size === 'xxsmall' || this.size === 'xsmall') {
      bodySize = 'small';
    } else if (this.size === 'small' || this.size === 'medium') {
      bodySize = 'medium';
    } else {
      bodySize = 'large';
    };

    return twMerge(
      'text-text-body',
      this.iconPosition == 'leading' ? 'order-1' : 'order-0',
      `body-${bodySize}`
    );
  };

  private get _iconSize() {
    if (this.size === 'xxsmall' || this.size === 'xsmall' || this.size === 'small') {
      return 'small';
    } else if (this.size === 'medium') {
      return 'medium';
    } else {
      return 'large';
    };
  };

  private get _accordionHeaderClass() {
    return twMerge(
      'flex items-center gap-100 flex-1',
      this.iconPosition == 'leading' ? 'order-1' : 'order-0'
    );
  }

  private get _accordionContentClass() {
    return this.showBottomDivider ? 'pb-200' : '';
  }

  render() {
    const iconName = this.expanded ? 'expand-show-less' : 'expand-show-more';

    return (
      <Host>
        {this.showTopDivider && <wdpr-divider />}

        <section class={baseClass}>
          <div class={toggleClass}
            role="button"
            aria-controls={this._internalId}
            aria-expanded={this.expanded ? 'true' : 'false'}
            aria-label={this.a11yLabel || undefined}
            onClick={this._handleClickEvent}
            onKeyDown={this._handleKeyDown}
            tabIndex={0}
          >
            <div class={this._accordionHeaderClass}>
              <slot name="icon"></slot>
              <div>
                <div class={this._titleClass} role="heading" aria-level="3">
                  {this.header}
                </div>
                {this.subheader && (
                  <div class={this._subheaderClass}>
                    {this.subheader}
                  </div>
                )}
              </div>
            </div>

            <span class={`${iconWrapperClass} ${this.iconPosition === 'leading' ? 'order-0' : 'order-1'}`} aria-hidden="true">
              <wdpr-icon-library
                icon={iconName}
                size={this._iconSize}
                decorative
              />
            </span>
          </div>
        </section>

        {this.expanded && (
          <div class={this._accordionContentClass} id={this._internalId}>
            <slot name="accordion-content"></slot>
          </div>
        )}

        {this.showBottomDivider && <wdpr-divider />}
      </Host>
    );
  }
}

const baseClass = 'flex py-200';
const toggleClass = `
flex items-center cursor-pointer gap-200 py-050 w-full focus-visible:outline-solid
focus-visible:outline-037 focus-visible:outline-offset-2 focus-visible:outline-stroke-actionable-focused
focus-visible:rounded-050
`;
const iconWrapperClass = `
text-text-actionable-alt-default transition-colors
hover:text-text-actionable-alt-hover active:text-text-actionable-alt-pressed
`;
const titleBaseClass = 'label-container flex-1 text-text-heading';
